ee:message.ee:set-payload:
%dw 2.0
output application/java
var requestedScopes = (attributes.queryParams.access_types splitBy ",") map trim($)
var allowedScopes = ["ACCOUNT_BASIC", "TRANSACTIONS", "CUSTOMER_CONTACT"]
var invalidScopes = requestedScopes filter (!contains(allowedScopes, $))
---
{
    requestedScopes: requestedScopes,
    allowedScopes: allowedScopes,
    invalidScopes: invalidScopes,
    isValid: isEmpty(invalidScopes)
}

ee:message.ee:set-attributes:
%dw 2.0
output application/java
---
{
    statusCode: 302,
    headers: {
        "Location": payload.authorizationUrl,
        "Cache-Control": "no-cache, no-store, must-revalidate",
        "Pragma": "no-cache",
        "Expires": "0"
    }
}

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    "success": true,
    "tokens": {
        access_token: payload.tokens.access_token,
        id_token: payload.tokens.id_token,
        token_type: payload.tokens.token_type,
        expires_at: payload.tokens.expires_at,
        session_id: payload.tokens.session_id
    }
}
